import { NextRequest, NextResponse } from "next/server";
import { Liveblocks } from "@liveblocks/node";

const COLORS = [
  "#FF6900",
  "#FCB900",
  "#7BDCB5",
  "#00D084",
  "#8ED1FC",
  "#0693E3",
  "#ABB8C3",
  "#EB144C",
  "#F78DA7",
  "#9900EF",
];

function getColorForName(name: string): string {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return COLORS[Math.abs(hash) % COLORS.length];
}

const adjectives = [
  "Happy", "Swift", "Calm", "Brave", "Bright",
  "Cool", "Eager", "Kind", "Bold", "Wise",
];

const nouns = [
  "Panda", "Falcon", "Otter", "Tiger", "Dolphin",
  "Eagle", "Fox", "Bear", "Wolf", "Hawk",
];

function generateRandomName(): string {
  const adj = adjectives[Math.floor(Math.random() * adjectives.length)];
  const noun = nouns[Math.floor(Math.random() * nouns.length)];
  return `${adj}${noun}`;
}

export async function POST(request: NextRequest) {
  const secret = process.env.LIVEBLOCKS_SECRET_KEY;
  if (!secret) {
    return NextResponse.json(
      { error: "LIVEBLOCKS_SECRET_KEY is not set" },
      { status: 500 }
    );
  }

  let body: Record<string, string> = {};
  try {
    body = await request.json();
  } catch {
    // Body may be empty; treat as empty object
  }

  const username: string = body.username || generateRandomName();
  const roomId: string | undefined = body.roomId;

  const color = getColorForName(username);
  const userId = `user-${username.toLowerCase().replace(/\s+/g, "-")}`;

  const liveblocks = new Liveblocks({ secret });

  const session = liveblocks.prepareSession(userId, {
    userInfo: { name: username, color },
  });

  if (roomId) {
    session.allow(roomId, session.FULL_ACCESS);
  } else {
    // Allow access to all rooms (for test cases that don't specify a room)
    session.allow("*", session.FULL_ACCESS);
  }

  const { body: responseBody } = await session.authorize();

  // responseBody is a JSON string like {"token":"..."}
  const parsed = JSON.parse(responseBody);
  return NextResponse.json({ token: parsed.token });
}

"use client";

import { LiveblocksProvider, RoomProvider, ClientSideSuspense } from "@liveblocks/react/suspense";
import Editor from "./Editor";

function getUsername(): string {
  if (typeof window === "undefined") return "Anonymous";
  const stored = localStorage.getItem("liveblocks-username");
  if (stored) return stored;
  const name = `User ${Math.floor(Math.random() * 10000)}`;
  localStorage.setItem("liveblocks-username", name);
  return name;
}

export default function Room({ roomId }: { roomId: string }) {
  return (
    <LiveblocksProvider
      authEndpoint={async (room) => {
        const username = getUsername();
        const response = await fetch("/api/liveblocks-auth", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ roomId: room, username }),
        });
        return response.json();
      }}
    >
      <RoomProvider id={roomId}>
        <ClientSideSuspense fallback={<div>Loading room…</div>}>
          {() => <Editor />}
        </ClientSideSuspense>
      </RoomProvider>
    </LiveblocksProvider>
  );
}

"use client";

import { useCallback, useEffect, useState } from "react";
import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Collaboration from "@tiptap/extension-collaboration";
import CollaborationCursor from "@tiptap/extension-collaboration-cursor";
import * as Y from "yjs";
import { LiveblocksYjsProvider } from "@liveblocks/yjs";
import { useSelf, useOthers, useRoom } from "@liveblocks/react/suspense";

export default function Editor() {
  const room = useRoom();
  const self = useSelf();
  const others = useOthers();

  const [yDoc] = useState(() => new Y.Doc());
  const [provider, setProvider] = useState<LiveblocksYjsProvider | null>(null);

  useEffect(() => {
    const yjsProvider = new LiveblocksYjsProvider(room, yDoc);
    setProvider(yjsProvider);

    return () => {
      yjsProvider.destroy();
      yDoc.destroy();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [room]);

  const userInfo = self.info;

  const editor = useEditor({
    extensions: [
      StarterKit.configure({
        history: false,
      }),
      Collaboration.configure({
        document: yDoc,
      }),
      ...(provider
        ? [
            CollaborationCursor.configure({
              provider,
              user: {
                name: userInfo.name,
                color: userInfo.color,
              },
            }),
          ]
        : []),
    ],
    content: "",
    editorProps: {
      attributes: {
        class: "editor",
      },
    },
  });

  // Update collaboration cursor user info when it changes
  useEffect(() => {
    if (editor && provider) {
      // Re-configure the collaboration cursor when user info changes
      const cursorExtension = editor.extensionManager.extensions.find(
        (ext) => ext.name === "collaborationCursor"
      );
      if (cursorExtension) {
        cursorExtension.options.user = {
          name: userInfo.name,
          color: userInfo.color,
        };
        // Update awareness state
        provider.awareness.setLocalStateField("user", {
          name: userInfo.name,
          color: userInfo.color,
        });
      }
    }
  }, [editor, provider, userInfo.name, userInfo.color]);

  const setBold = useCallback(() => {
    editor?.chain().focus().toggleBold().run();
  }, [editor]);

  const setItalic = useCallback(() => {
    editor?.chain().focus().toggleItalic().run();
  }, [editor]);

  const setH1 = useCallback(() => {
    editor?.chain().focus().toggleHeading({ level: 1 }).run();
  }, [editor]);

  const setH2 = useCallback(() => {
    editor?.chain().focus().toggleHeading({ level: 2 }).run();
  }, [editor]);

  const setBulletList = useCallback(() => {
    editor?.chain().focus().toggleBulletList().run();
  }, [editor]);

  const allUsers = [self, ...others.toArray()];
  const connectedCount = allUsers.length;

  return (
    <main>
      <h1>Collaborative Editor</h1>

      <div className="connected-users">
        {allUsers.map((user) => (
          <span
            key={user.id ?? user.connectionId}
            className="connected-user"
            style={{ backgroundColor: user.info?.color || "#ccc" }}
          >
            {user.info?.name || "Anonymous"}
          </span>
        ))}
        <span data-testid="connected-count">{connectedCount} connected</span>
      </div>

      <div className="toolbar">
        <button data-testid="toolbar-bold" onClick={setBold}>
          <strong>B</strong>
        </button>
        <button data-testid="toolbar-italic" onClick={setItalic}>
          <em>I</em>
        </button>
        <button data-testid="toolbar-h1" onClick={setH1}>
          H1
        </button>
        <button data-testid="toolbar-h2" onClick={setH2}>
          H2
        </button>
        <button data-testid="toolbar-bullet-list" onClick={setBulletList}>
          • List
        </button>
      </div>

      <div data-testid="tiptap-editor">
        <EditorContent editor={editor} />
      </div>
    </main>
  );
}

