* { box-sizing: border-box; }
body { font-family: system-ui, sans-serif; margin: 0; padding: 24px; }
button { cursor: pointer; }

.toolbar { display: flex; gap: 6px; margin-bottom: 12px; }
.toolbar button { padding: 4px 10px; }

.editor {
  border: 1px solid #ccc;
  padding: 12px;
  min-height: 200px;
  border-radius: 4px;
}
.editor:focus { outline: 2px solid #4a90e2; }

.connected-users { display: flex; gap: 10px; margin-bottom: 8px; flex-wrap: wrap; align-items: center; }
.connected-user { padding: 2px 8px; border-radius: 999px; background: #eee; font-size: 13px; color: #fff; }

